 174: export const archiveExpiredHotEvents = async (): Promise<number> => {
 175:   const conn = await dbPool.getConnection();
 176:   try {
 177:     await conn.beginTransaction();
 178: 
 179:     const [candidates] = await conn.query<{ id: number }[]>(
 180:       `SELECT id
 181:        FROM behavior_events_hot
 182:        WHERE server_recorded_at < DATE_SUB(UTC_TIMESTAMP(), INTERVAL 90 DAY)
 183:        ORDER BY id ASC
 184:        LIMIT 2000`
 185:     );
 186: 
 187:     if (candidates.length === 0) {
 188:       await conn.commit();
 189:       return 0;
 190:     }
 191: 
 192:     const ids = candidates.map((row) => row.id);
 193:     const placeholders = ids.map(() => '?').join(',');
 194: 
 195:     await conn.query(
 196:       `INSERT INTO behavior_events_archive
 197:         (source_hot_id, idempotency_key, event_type, user_id, resource_type, resource_id, client_recorded_at, server_recorded_at, metadata_json)
 198:        SELECT id, idempotency_key, event_type, user_id, resource_type, resource_id, client_recorded_at, server_recorded_at, metadata_json
 199:        FROM behavior_events_hot
 200:        WHERE id IN (${placeholders})`,
 201:       ids
 202:     );
 203: 
 204:     await conn.query(`DELETE FROM behavior_events_hot WHERE id IN (${placeholders})`, ids);
 205: 
 206:     await conn.commit();
 207:     return ids.length;
 208:   } catch (error) {
 209:     await conn.rollback();
 210:     throw error;
 211:   } finally {
 212:     conn.release();
 213:   }
 214: };
