  66: 
  67:   const usage = await getWithdrawalWindowUsage(leaderUserId);
  68:   const remainingDailyAmount = Number(
  69:     Math.max(0, DAILY_WITHDRAWAL_LIMIT - usage.todayAmount).toFixed(2),
  70:   );
  71:   const remainingWeeklyCount = Math.max(
  72:     0,
